import{_ as t,o as i,c as a,ag as r}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse(`{"title":"Alias Interactifs : commandes sûres avec confirmations | Dotfiles (FR)","titleTemplate":":title","description":"Alias shell qui ajoutent des confirmations avant rm, mv et cp. Évitez les suppressions accidentelles.","frontmatter":{"title":"Alias Interactifs : commandes sûres avec confirmations","description":"Alias shell qui ajoutent des confirmations avant rm, mv et cp. Évitez les suppressions accidentelles.","lang":"fr-FR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Interactifs : commandes sûres avec confirmations preview","canonical":"/fr/aliases/interactive/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Interactifs : commandes sûres avec confirmations","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Interactifs | Dotfiles","permalink":"/fr/aliases/interactive/","sidebar":true,"meta":[{"name":"keywords","content":"alias interactifs, sécurité shell, confirmation rm, cp interactif, prompt mv, dotfiles, alias bash"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Interactifs | Dotfiles"},{"name":"twitter:description","content":"Alias shell qui ajoutent des confirmations avant rm, mv et cp."},{"name":"og:title","content":"Alias Interactifs | Dotfiles"},{"name":"og:description","content":"Alias shell qui ajoutent des confirmations avant rm, mv et cp."},{"name":"og:image:alt","content":"Dotfiles - Conçus pour s'adapter à votre vie de shell"},{"name":"og:locale","content":"fr_FR"}]},"headers":[],"relativePath":"fr/aliases/interactive/index.md","filePath":"fr/aliases/interactive/index.md","lastUpdated":1773010926000}`),s={name:"fr/aliases/interactive/index.md"};function o(n,e,d,c,l,m){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="alias-interactifs" tabindex="-1">Alias Interactifs <a class="header-anchor" href="#alias-interactifs" aria-label="Permalink to &quot;Alias Interactifs&quot;">​</a></h1><p>Commandes shell sûres avec confirmation avant les opérations destructrices.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Dotfiles banner"></p><h2 id="apercu" tabindex="-1">Aperçu <a class="header-anchor" href="#apercu" aria-label="Permalink to &quot;Aperçu&quot;">​</a></h2><p>Les alias interactifs ajoutent des confirmations aux commandes qui peuvent modifier ou supprimer des fichiers de façon irréversible. Définis dans <code>interactive.aliases.sh</code> et chargés automatiquement par chezmoi, ils réduisent les risques de perte de données en demandant une confirmation.</p><h2 id="reference" tabindex="-1">Référence <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Référence&quot;">​</a></h2><h3 id="operations-sur-fichiers" tabindex="-1">Opérations sur fichiers <a class="header-anchor" href="#operations-sur-fichiers" aria-label="Permalink to &quot;Opérations sur fichiers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Description</th></tr></thead><tbody><tr><td><code>cp</code></td><td>Copier fichiers et dossiers en mode interactif avec sortie verbeuse. Demande confirmation avant écrasement.</td></tr><tr><td><code>mv</code></td><td>Déplacer/renommer en mode interactif avec sortie verbeuse. Demande confirmation avant écrasement.</td></tr><tr><td><code>ln</code></td><td>Créer des liens symboliques en mode interactif avec sortie verbeuse. Demande confirmation avant écrasement.</td></tr></tbody></table><h3 id="suppression-de-fichiers" tabindex="-1">Suppression de fichiers <a class="header-anchor" href="#suppression-de-fichiers" aria-label="Permalink to &quot;Suppression de fichiers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Description</th></tr></thead><tbody><tr><td><code>rm</code></td><td>Supprimer fichiers/dossiers en mode interactif avec sortie verbeuse. Demande confirmation pour chaque suppression.</td></tr><tr><td><code>del</code></td><td>Supprimer fichiers/dossiers en mode interactif et récursif avec sortie verbeuse. Demande confirmation pour chaque suppression.</td></tr><tr><td><code>zap</code></td><td>Alias de <code>rm</code>. Supprime de manière interactive avec sortie verbeuse.</td></tr></tbody></table><h3 id="gestion-de-la-corbeille" tabindex="-1">Gestion de la corbeille <a class="header-anchor" href="#gestion-de-la-corbeille" aria-label="Permalink to &quot;Gestion de la corbeille&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Description</th></tr></thead><tbody><tr><td><code>bin</code></td><td>Supprimer tous les fichiers de la corbeille (<code>~/.Trash</code>) de façon forcée et récursive.</td></tr></tbody></table><h3 id="permissions-et-utilitaires" tabindex="-1">Permissions et utilitaires <a class="header-anchor" href="#permissions-et-utilitaires" aria-label="Permalink to &quot;Permissions et utilitaires&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Description</th></tr></thead><tbody><tr><td><code>chmod</code></td><td>Modifier les permissions avec sortie verbeuse.</td></tr><tr><td><code>chown</code></td><td>Modifier propriétaire et groupe avec sortie verbeuse.</td></tr><tr><td><code>diff</code></td><td>Comparer deux fichiers en format unifié.</td></tr><tr><td><code>grep</code></td><td>Rechercher un motif avec numéros de ligne et insensibilité à la casse.</td></tr><tr><td><code>mkdir</code></td><td>Créer un répertoire avec parents et sortie verbeuse.</td></tr></tbody></table>',14)])])}const u=t(s,[["render",o]]);export{p as __pageData,u as default};
